#include <bits/stdc++.h>using namespace std;void solve() {    string s;    cin >> s;    int64_t curr = 0, max_cnt = 0;    for (auto &c : s) {        if (c == '1')            max_cnt = max(max_cnt, ++curr);        else            curr = 0;    }    if (max_cnt == s.length()) {        cout << max_cnt * max_cnt << '\n';        return;    }    s += s;    curr = 0, max_cnt = 0;    for (auto &c : s) {        if (c == '1')            max_cnt = max(max_cnt, ++curr);        else            curr = 0;    }    max_cnt++;    cout << max_cnt/2 * (max_cnt - max_cnt/2) << '\n';} int main() {    ios::sync_with_stdio(false);    cin.tie(nullptr);    int t = 1;    cin >> t;    while (t--) {        solve();    }}